#r "/home/runner/.nuget/packages/microsoft.agents.ai/1.3.0/lib/net9.0/Microsoft.Agents.AI.dll"
#r "/home/runner/.nuget/packages/microsoft.extensions.ai.abstractions/9.6.0/lib/net9.0/Microsoft.Extensions.AI.Abstractions.dll"
#r "/home/runner/.nuget/packages/microsoft.extensions.ai/9.6.0/lib/net9.0/Microsoft.Extensions.AI.dll"

using System.Reflection;

var asm = Assembly.LoadFrom("/home/runner/.nuget/packages/microsoft.agents.ai/1.3.0/lib/net9.0/Microsoft.Agents.AI.dll");

foreach (var type in asm.GetExportedTypes().OrderBy(t => t.FullName))
{
    Console.WriteLine($"\n=== {type.FullName} ===");
    if (type.BaseType != null && type.BaseType != typeof(object))
        Console.WriteLine($"  Base: {type.BaseType.FullName}");
    foreach (var iface in type.GetInterfaces().Where(i => !i.FullName?.StartsWith("System") ?? false))
        Console.WriteLine($"  Implements: {iface.FullName}");
    foreach (var ctor in type.GetConstructors())
        Console.WriteLine($"  ctor({string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var prop in type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  prop {prop.PropertyType.Name} {prop.Name} {{ {(prop.CanRead?"get;":"")}{(prop.CanWrite?"set;":"")} }}");
    foreach (var method in type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
        Console.WriteLine($"  method {method.ReturnType.Name} {method.Name}({string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}
EOF
